mapper.select:
SELECT id, memory_id, diagnosis_id, service_name, alert_rule, severity, symptom_summary, evidence_summary, root_cause_category, root_cause_summary, remediation_summary, confidence, review_status, time_window_json, tags, similarity_text, source_record_json, create_time, update_time FROM ops_historical_incident_memory WHERE 1 = 1
AND service_name = #{serviceName}
AND ( similarity_text LIKE CONCAT('%', #{keyword}, '%') OR alert_rule LIKE CONCAT('%', #{keyword}, '%') OR root_cause_summary LIKE CONCAT('%', #{keyword}, '%') OR tags LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY confidence DESC, create_time DESC LIMIT #{limit}
